import React, { useState } from 'react';
import Navbar from '../components/Navbar';
import TaskCard from '../components/TaskCard';
import { motion } from 'framer-motion';
import { Plus } from 'lucide-react';

const Dashboard = () => {
  // Dummy data for now (Baad mein backend se connect karenge)
  const [tasks] = useState([
    { title: "Portfolio 3D Animation", description: "Framer motion use karke 3D tilt effect lagana hai.", priority: "High" },
    { title: "Backend API Integration", description: "Node.js aur MongoDB ke saath connect karna hai.", priority: "Normal" },
    { title: "Railway Deployment", description: "Final submission ke liye project live karna hai.", priority: "High" },
  ]);

  return (
    <div className="min-h-screen text-white">
      <Navbar />
      
      <main className="pt-32 pb-12 px-6 max-w-7xl mx-auto">
        <header className="flex justify-between items-center mb-10">
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
            <h1 className="text-4xl font-bold bg-gradient-to-r from-white to-gray-500 bg-clip-text text-transparent">
              Welcome, Aditya
            </h1>
            <p className="text-gray-400 mt-2">You have {tasks.length} active tasks today.</p>
          </motion.div>
          
          <motion.button 
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            className="flex items-center gap-2 bg-indigo-600 px-6 py-3 rounded-2xl font-bold shadow-lg shadow-indigo-500/20"
          >
            <Plus size={20} /> New Task
          </motion.button>
        </header>

        {/* Bento Grid Layout */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {tasks.map((task, index) => (
            <TaskCard key={index} task={task} />
          ))}
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
